#include <esp_sleep.h>

void setup() {
  Serial.begin(115200);
  // Wake on GPIO 33 going LOW
  esp_sleep_enable_ext0_wakeup(GPIO_NUM_33, 0);
  // Or wake after 60 seconds
  esp_sleep_enable_timer_wakeup(60ULL * 1000000ULL);

  Serial.print("wake reason: ");
  Serial.println((int)esp_sleep_get_wakeup_cause());

  // ... do work ...

  Serial.println("sleeping");
  esp_deep_sleep_start();
}

void loop() {}
```

Deep sleep current on a stock ESP32-DevKitC: 5-10 mA (the on-board 5 V to 3.3 V LDO and USB chip dominate). On a custom board with just the ESP32-WROOM-32 + a bare LDO: 10 uA. ext0 wakeup uses RTC IO pins only (GPIO 0, 2, 4, 12-15, 25-27, 32-39); the rest do not wake.
